INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3020_L017$$, 2026, $$The AIM-9X Block II/II+ Sidewinder (AIM-9X Blk II/II+) continues the evolution of the AIM-9 series of missiles. This missile program delivers a launch and leave, air combat munition that uses passive Infrared (IR)
 energy to acquire and track enemy air targets and complements the radar guided Advanced Medium Range Air-to-Air Missile (AMRAAM). The inner-boundry missile provides first shot, first kill opportunities while
 conducting air combat maneuvering which is essential for aircrew survival. The AIM-9X provides these opportunities with unmatched offensive and defensive capabilities against threats within the inner boundary,
 even when IR countermeasures are employed.

 The AIM-9X also provides air superiority in the Beyond Visual Range (BVR) air-to-air battle. Anti-tamper features have been incorporated to protect improvements inherent in this design. The AIM-9X Block II
 missile is critical for projecting power and winning decisively against current and emerging threats.

 AIM-9X is a Post Milestone C, Acquisition Category IC (ACAT-IC) joint service program led by the Department of the Navy (DoN). In June 2011, the Milestone Decision Authority (MDA) established the AIM-9X
 Block II missile program which was approved for entry at Milestone C for Low Rate Initial Production (LRIP). The Block I program ended with the Sec 2366 A/B certification and Acquisition Program Baseline
 (APB) for AIM-9X Block II approval on December 23, 2011. In August 2015, the program received approval for Full Rate Production (FRP), and the APB was re-established.

 In December 2017, the program began to procure a third variant of the missile labeled the AIM-9X Block II PLUS (Block II+) to satisfy the requirements of the Joint Strike Fighter platform. This version of the
 missile is being produced on the same production line as the AIM-9X Block II missile. For contracting purposes, the nomenclature of the AIM-9X Block II missile is identified as AIM-9X-2 or AIM-9X-4 and the
 AIM-9X Block II+ missile is identified as AIM-9X-3. The AIM-9X-4 variants are the System Improvement Program (SIP) III configuration with upgraded hardware for obsolescence that cut into Lot 21.

 In February 2019, the APB for DoN and USAF was revised to increase total missile procurements from 6,000 to 11,635 missiles and to extend USAF missile procurements through 2035. The current APB
 quantity of 11,635 missiles is made up of 5,326 DoN missiles and 6,309 USAF missiles.

 Funding for this exhibit contained in PE 0207161F.

 Funding may be used to address Diminishing Manufacturing Source (DMS) issues.

 This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":17,"src_title":"Sidewinder (AIM-9X)","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Missile Procurement.pdf$$, 123, 123, $$8d91aeef1ab83f3e$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1611_L013$$, 2026, $$Detect, classify, localize and track submerged submarines under all environmental conditions at long range from ASW ships, using bottom reflected and convergence zone acoustic paths. Starting in FY20, the
 Multi-Function Towed Array (MFTA) sensor along with the Handling and Stowage Gear (H&SG) is included as part of in-line construction of new DDG-51 class ships.

