INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_0300_L099$$, 2027, $$This effort provides modifications to seven C-27J aircraft with equipment to improve reliability and maintainability, correct deficiencies, address obsolescence, incorporate mission enhancements, and make
 critical safety changes. Current projects include cockpit resets and upgrades. There is no associated Research, Development, Test and Evaluation funding.

 FY 2027 BASE PROGRAM JUSTIFICATION: Procures and installs low-cost modifications to C-27J mission systems to enhance aircraft capabilities such as, but not limited to, avionics, sensor, datalink, electrical
 and communication upgrades to meet mission requirements and allow for continued support of Special Operations Forces.

 FY 2026 to FY 2027 increase of $11.400 million supports procurement of avionics upgrades for two C-27J aircraft cockpits. The C-27J Avionics Block Upgrade Program (AVBUP) addresses critical obsolescence
 and safety issues by replacing components and provides corresponding updates. AVBUP is required to ensure the C-27J meets mandatory Federal Aviation Administration requirements to operate.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 United States Special Operations Command                                                                                                      Date: April 2026
