INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L051$$, 2026, $$This program, P-3A Mod 8980, Embedded Diagnostic System II, is a new start.
 The EDS-II replacement program is a comprehensive permanent sustainment modification designed to replace the obsolete auxiliary maintenance computer, the no longer procurable Personal Computer
 Interface Unit, and key loading panel with a modern computing architecture and permanent ancillary equipment. The modification will simplify the design, enable ethernet loading of mission software, allow for
 back up radio cryptographic key loading, combat obsolete data transfer medium, and drive non-mission capable rates down by 900+ hours per year. Without this modification, aircraft project to be grounded$$, $$$$, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":51,"src_title":"C-5","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 446, 446, $$0f2bc2f159ba761d$$, $$2026-05-10T04:06:02.992954+00:00$$) ON CONFLICT DO NOTHING;
