INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3020_L002$$, 2026, $$In order to save 81 weeks of schedule, HACTS 2.0 is requesting AP to order long lead materials prior to EMD completion and begin assembly as forecasted in 1QFY28. Lead times range from 31-81 weeks,
 any items not procured with AP will result in a minimum of 12 months delay when factoring in CR. Advance procurement is urgently needed to maintain the operational status of the current HACTS system,
 the platform for certifying mandated bi-annual Launch Control Center (LCC) updates. Failure to do so will result in LCCs operating with out-of-date software, potentially leading to target synchronization errors,
 inability to decrypt launch execution messages and misalignment with the Nuclear Triad. Delaying procurement of Cables, Terminal Boards, and Connectors introduces significant obsolescence risk, potentially
 requiring a costly system redesign, impacting targeting capabilities and timing requirements, thus jeopardizing national security.

 (†)
       indicates the presence of Contract Data presented in the associated P-5 Item's P-5a exhibit.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":2,"src_title":"Missile Replacement Eq-Ballistic","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Missile Procurement.pdf$$, 46, 46, $$4fc7bd3a22b3a1a2$$, $$2026-05-10T04:06:02.992954+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L021$$, 2026, $$MUOS Ground System Updates will correct functional and cyber defects and address hardware and software obsolescence. Configuration updates are deployed as modification kits which are variable in scope
 and require significant non-recurring engineering and integration testing to ensure hardware and software system updates do not adversely impact ongoing operations. A specific modification kit's scope depends
 primarily on the magnitude and severity of the functional defects, cybersecurity defects and vulnerabilities, and obsolescence.

 Funding is for five Ground System updates for each of the four RAFs and three Ground System updates for each of the two Satellite Control Facilities in each fiscal year through the FYDP. The Ground
 System updates address hardware and software defect resolution as well as hardware degradation. The hardware/software updates are installed at each ground site as part of the MUOS operational end item
 requirements; ground system defect resolution includes associated engineering, integration, test, and delivery efforts to address cybersecurity vulnerabilities, and corrects issues to ensure readiness levels
 support the warfighter narrowband SATCOM requirements. To address hardware degradation, obsolete items will be replaced in phases in each fiscal year and can include GPS-based Timing and Frequency
 Distribution System, data back-up and recovery, and Earth Terminal Antenna components. Obsolete software components include Microsoft OS-based workstations and servers, Solaris OS based components,
 and Redhat/Linux OS-based components. Addressing software obsolescence may also include hardware replacement to support the new OS. Modification kit costs vary between the ground site locations
 and depend on the size and complexity of the infrastructure footprint of each modification kit's ground site destination. For example, because the Wahiawa ground site contains approximately 45-50% of the
 total ground segment's hardware and software infrastructure, this site's mod kits require a similar percentage of the overall budget for mod kits. Similarly, Northwest contains approximately 20% of the ground
 segment's hardware and software infrastructure, Niscemi and Geraldton each contain approximately 15% of the infrastructure, and the 10th Space Operations Squadron (SOPS) locations contain approximately
 2% of the infrastructure.

 Additionally, funding will be used for integration and testing of the necessary hardware and software upgrade options which address system deficiencies.

 Milestone/Development Status

 Development is on-track to meet system update targets and timelines.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":21,"src_title":"Mobile User Objective System","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 108, 108, $$42029b38b3bcc581$$, $$2026-05-10T04:06:02.992954+00:00$$) ON CONFLICT DO NOTHING;
